return ['messages'=>['1b478853e99745b3889059b3ce289f5f'=>'El día 3 de mayo realizamos una excursión a Zerain y Segura.<br>','3eef004f11183cb3cdf5bbd56fb28feb'=>'A la tarde tras la comida nos dirigimos a Segura. Allí pudimos disfrutar de una visita guiada para más tarde degustar un delicioso queso en la casa rural Ondarre.<br> ','8068e948328ffe970c634fa6a3005235'=>'Con una climatología maravillosa visitamos en Zerain: la Serrería Hidráulica de Larrondo, el Coto Minero con sus hornos y centro de interpretación y el Museo Etnográfico.<br>','Arratsaldean, bazkalostean, Segurara abiatu ginen. Bertan bisita gidatu batez gozatu ahal izan genuen, geroago Ondarre landetxean gazta gozo bat dastatzeko.'=>'A la tarde tras la comida nos dirigimos a Segura. Allí pudimos disfrutar de una visita guiada para más tarde degustar un delicioso queso en la casa rural Ondarre.<br> ','Beste egun bizi bat!!!'=>'Otro día intenso!!!<br>','Eguraldi zoragarriarekin bisitatu genuen Zerain, Larrondoko Zerrategi Hidraulikoa, Meatze Barrutia bere labe eta interpretazio zentroarekin eta Museo Etnografikoa.'=>'Con una climatología maravillosa visitamos en Zerain: la Serrería Hidráulica de Larrondo, el Coto Minero con sus hornos y centro de interpretación y el Museo Etnográfico.<br>','Maiatzaren 3an Zerain eta Segurara txangoa egin genuen.'=>'El día 3 de mayo realizamos una excursión a Zerain y Segura.<br>','c314bb7da10de45894c7148ab9f77db5'=>'Otro día intenso!!!<br>']];
